// GradientMesh.tsx
import React from 'react';
import {StyleSheet, useWindowDimensions} from 'react-native';
import {Canvas, Circle, RadialGradient, vec, BlurMask, Group} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
export function GradientMesh({colors = ['#FF3B5C','#0A84FF','#BF5AF2']}: {colors?: string[]}) {
  const {width: SW, height: SH} = useWindowDimensions();
  const t = useSharedValue(0);
  useFrameCallback(({timeSinceFirstFrame}) => { t.value = timeSinceFirstFrame / 1000; });
  const blob = (i: number, color: string) => { const phase = i * 2.1; const cx = useDerivedValue(() => SW/2 + Math.sin(t.value * 0.2 + phase) * 80); const cy = useDerivedValue(() => SH/2 + Math.cos(t.value * 0.15 + phase) * 100); const r = SH * 0.4; return (<Circle key={i} cx={cx} cy={cy} r={r}><RadialGradient c={vec(0, 0)} r={r} colors={[color + 'AA', color + '00']}/><BlurMask blur={40} style='normal'/></Circle>); };
  return (<Canvas style={StyleSheet.absoluteFill}><Group>{colors.map((c, i) => blob(i, c))}</Group></Canvas>);
}

// ProgressCheckmark.tsx
import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, useDerivedValue, withTiming, Easing} from 'react-native-reanimated';
export function ProgressCheckmark({progress, complete, size = 22}: {progress: number; complete: boolean; size?: number}) {
  const p = useSharedValue(0); const c = useSharedValue(0);
  useEffect(() => { p.value = withTiming(progress, {duration: 300}); }, [progress]);
  useEffect(() => { c.value = withTiming(complete ? 1 : 0, {duration: 360, easing: Easing.bezier(0.32, 0, 0.32, 1)}); }, [complete]);
  const r = size/2 - 2;
  const ringPath = useDerivedValue(() => { const path = Skia.Path.Make(); const sweep = (complete ? 1 : p.value) * 360; path.addArc({x: 2, y: 2, width: r*2, height: r*2}, -90, sweep); return path; });
  const checkPath = useDerivedValue(() => { const path = Skia.Path.Make(); const x1 = size * 0.28; const y1 = size * 0.50; const x2 = size * 0.45; const y2 = size * 0.66; const x3 = size * 0.72; const y3 = size * 0.36; const t = c.value; if (t <= 0) return path; path.moveTo(x1, y1); const segA = Math.min(t / 0.5, 1); path.lineTo(x1 + (x2 - x1) * segA, y1 + (y2 - y1) * segA); if (t > 0.5) { const segB = (t - 0.5) / 0.5; path.lineTo(x2 + (x3 - x2) * segB, y2 + (y3 - y2) * segB); } return path; });
  const ringOpacity = useDerivedValue(() => 1 - c.value * 0.4);
  return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Path path={ringPath} style='stroke' strokeWidth={2} color='#0A84FF' strokeCap='round' opacity={ringOpacity}/><Path path={checkPath} style='stroke' strokeWidth={2.5} color='#0A84FF' strokeCap='round' strokeJoin='round'/></Canvas></View>);
}

