// ThemeProvider.tsx
import React, {createContext, useContext, useState, useEffect} from 'react';
import {useColorScheme} from 'react-native';
import {MMKV} from 'react-native-mmkv';
const storage = new MMKV();
type Mode = 'auto'|'light'|'dark';
type Contrast = 'normal'|'outdoor';
const THEMES = { lightNormal: {bg:'#FAFAFA', text:'#1C1C1E', muted:'#6B6B6B', accent:'#007AFF'}, lightOutdoor: {bg:'#FFFFFF', text:'#000000', muted:'#3A3A3C', accent:'#0040FF'}, darkNormal: {bg:'#000000', text:'#FFFFFF', muted:'#8E8E93', accent:'#0A84FF'}, darkOutdoor: {bg:'#000000', text:'#FFFFFF', muted:'#C7C7CC', accent:'#FFD60A'}};
const Ctx = createContext({colors: THEMES.darkNormal, mode: 'auto' as Mode, contrast: 'normal' as Contrast, setMode: (m: Mode) => {}, setContrast: (c: Contrast) => {}});
export const useTheme = () => useContext(Ctx);
export function ThemeProvider({children}: {children: React.ReactNode}) {
  const sys = useColorScheme();
  const [mode, setMode] = useState<Mode>((storage.getString('mode') as Mode) ?? 'auto');
  const [contrast, setContrast] = useState<Contrast>((storage.getString('contrast') as Contrast) ?? 'normal');
  useEffect(() => { storage.set('mode', mode); }, [mode]);
  useEffect(() => { storage.set('contrast', contrast); }, [contrast]);
  const effective = mode === 'auto' ? sys : mode;
  const colors = effective === 'dark' ? (contrast === 'outdoor' ? THEMES.darkOutdoor : THEMES.darkNormal) : (contrast === 'outdoor' ? THEMES.lightOutdoor : THEMES.lightNormal);
  return <Ctx.Provider value={{colors, mode, contrast, setMode, setContrast}}>{children}</Ctx.Provider>;
}

