import React, {useState} from 'react';
import {StyleSheet, View, Text, Pressable, LayoutChangeEvent} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function SegmentedControl({options, value, onChange}: {options: string[]; value: number; onChange: (i: number) => void}) {
  const [width, setWidth] = useState(0);
  const segW = (width - 4) / options.length;
  const x = useSharedValue(2 + value * segW);
  React.useEffect(() => { x.value = withSpring(2 + value * segW, {damping: 22, stiffness: 260}); }, [value, segW]);
  const pillStyle = useAnimatedStyle(() => ({transform: [{translateX: x.value}], width: segW}));
  return (<View style={s.wrap} onLayout={(e: LayoutChangeEvent) => setWidth(e.nativeEvent.layout.width)}><Animated.View style={[s.pill, pillStyle]}/>{options.map((opt, i) => (<Pressable key={opt} onPress={() => { Haptics.selectionAsync(); onChange(i); }} style={[s.seg, {width: segW}]}><Text style={[s.text, value === i && s.textActive]} numberOfLines={1}>{opt}</Text></Pressable>))}</View>);
}
