import React from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS, interpolate, Extrapolation} from 'react-native-reanimated';
import {router} from 'expo-router';
export function SwipeDownDismiss({children}: {children: React.ReactNode}) {
  const y = useSharedValue(0);
  const ctx = useSharedValue(0);
  const close = () => router.back();
  const pan = Gesture.Pan().activeOffsetY(10).onStart(() => { ctx.value = y.value; }).onUpdate(e => { y.value = Math.max(0, ctx.value + e.translationY); }).onEnd(e => { if (y.value > 100 || e.velocityY > 800) { y.value = withTiming(800, {duration: 220}, () => runOnJS(close)()); } else { y.value = withSpring(0, {damping: 22, stiffness: 240}); }});
  const contentStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}, {scale: interpolate(y.value, [0, 300], [1, 0.9], Extrapolation.CLAMP)}]}));
  const bgStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [0, 300], [1, 0], Extrapolation.CLAMP)}));
  return (<View style={{flex:1}}><Animated.View style={[StyleSheet.absoluteFill, {backgroundColor:'#000'}, bgStyle]}/><GestureDetector gesture={pan}><Animated.View style={[{flex:1}, contentStyle]}>{children}</Animated.View></GestureDetector></View>);
}

