export function VoiceRecorder({onComplete}: {onComplete: (uri: string) => void}) {
  const [recording, setRecording] = useState<Audio.Recording | null>(null);
  const [peaks, setPeaks] = useState<number[]>([]);
  const start = async () => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); const {granted} = await Audio.requestPermissionsAsync(); if (!granted) return; await Audio.setAudioModeAsync({allowsRecordingIOS: true, playsInSilentModeIOS: true}); const rec = new Audio.Recording(); await rec.prepareToRecordAsync({...Audio.RecordingOptionsPresets.HIGH_QUALITY, isMeteringEnabled: true}); rec.setOnRecordingStatusUpdate(status => { if (status.metering !== undefined) { setPeaks(p => [...p.slice(-99), Math.max(0, (status.metering + 60) / 60)]); }}); rec.setProgressUpdateInterval(80); await rec.startAsync(); setRecording(rec); };
  const stop = async () => { if (!recording) return; Haptics.selectionAsync(); await recording.stopAndUnloadAsync(); const uri = recording.getURI(); setRecording(null); setPeaks([]); if (uri) onComplete(uri); };
  const longPress = Gesture.LongPress().minDuration(200).onStart(() => start()).onEnd(() => stop());
  return (<View style={s.root}>{recording && <Waveform peaks={peaks} width={300} durationMs={1} positionMs={0} isPlaying={false} onSeek={() => {}}/>}<GestureDetector gesture={longPress}><Pressable style={[s.btn, recording && s.btnActive]}><Text style={s.btnText}>{recording ? '■ RECORDING' : '⏺ HOLD'}</Text></Pressable></GestureDetector></View>);
}
