import React, {useEffect, useState, useRef} from 'react';
import {Polyline} from 'react-native-maps';
import MapView from 'react-native-maps';
import {useSharedValue, withTiming, useAnimatedReaction, runOnJS, Easing} from 'react-native-reanimated';
export function RouteReveal({coords, mapRef}: {coords: {latitude: number; longitude: number}[]; mapRef: React.RefObject<MapView>}) {
  const progress = useSharedValue(0);
  const [visibleCount, setVisibleCount] = useState(0);
  useEffect(() => { progress.value = 0; progress.value = withTiming(1, {duration: 1200, easing: Easing.bezier(0.32, 0.72, 0, 1)}); mapRef.current?.fitToCoordinates(coords, {edgePadding: {top: 100, bottom: 100, left: 40, right: 40}, animated: true}); }, [coords]);
