import React, {useState, useMemo} from 'react';
import {StyleSheet, View, Text, Pressable, useWindowDimensions} from 'react-native';
import * as Haptics from 'expo-haptics';
const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
export function DateRangePicker({year, month, onChange}: {year: number; month: number; onChange: (start: Date, end: Date | null) => void}) {
  const {width: SW} = useWindowDimensions();
  const cell = (SW - 64) / 7;
  const [start, setStart] = useState<Date | null>(null);
  const [end, setEnd] = useState<Date | null>(null);
  const days = useMemo(() => { const first = new Date(year, month, 1); const offset = first.getDay(); const lastDay = new Date(year, month + 1, 0).getDate(); const arr: (Date | null)[] = Array(offset).fill(null); for (let d = 1; d <= lastDay; d++) arr.push(new Date(year, month, d)); return arr; }, [year, month]);
  const pick = (d: Date) => { Haptics.selectionAsync(); if (!start || (start && end)) { setStart(d); setEnd(null); onChange(d, null); } else if (d < start) { setStart(d); setEnd(null); onChange(d, null); } else { setEnd(d); onChange(start, d); }};
  const inRange = (d: Date) => start && end && d >= start && d <= end;
  const isEdge = (d: Date) => (start && d.getTime() === start.getTime()) || (end && d.getTime() === end.getTime());
  return (<View style={s.root}><Text style={s.title}>{MONTHS[month]} {year}</Text><View style={s.grid}>{days.map((d, i) => (<View key={i} style={{width: cell, height: cell, alignItems: 'center', justifyContent: 'center'}}>{d ? (<Pressable onPress={() => pick(d)} style={[s.cell, isEdge(d) && s.cellEdge, inRange(d) && !isEdge(d) && s.cellRange]}><Text style={[s.cellText, isEdge(d) && s.cellTextEdge]}>{d.getDate()}</Text></Pressable>) : null}</View>))}</View></View>);
}
